class Plain { int x; };
class WithVirtual { int x; virtual void f() {} };

int main() {
    if (sizeof(WithVirtual) > sizeof(Plain))
        std::cout << "vptr adds overhead: yes\n";
    else
        std::cout << "vptr adds overhead: no\n";
    return 0;
}

