solution_code:
#include <iostream>

class Animal {
public:
    virtual void speak() const { std::cout << "Animal::speak\n"; }
    virtual void move() const { std::cout << "Animal::move\n"; }
};

class Dog : public Animal {
public:
    void speak() const override { std::cout << "Dog::speak\n"; }
    // Dog does NOT override move()
};

int main() {
    Animal a;
    Dog d;
    Animal* ptrs[2] = { &a, &d };
    ptrs[0]->move();
    ptrs[1]->speak();
    ptrs[1]->move();
    return 0;
}
